/**
 *
 * @param instanceMap
 * @param event
 * @constructor
 */
export function LegendSizeSliderBrushListener(instanceMap, event) {
    let eventManager = this,
        { type, selection } = event,
        data = eventManager.getData(instanceMap, type, selection);

    eventManager.associateBehaviours(instanceMap, type, data, selection, event);
}
